mapper.select:
SELECT PROP_CD, CMPX_CD, LAT, LNG, NEARBY_RADIUS
  FROM INV.CONCIERGE_PROPERTY_EXT
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}

mapper.update:
UPDATE INV.CONCIERGE_AMENITY_REQ
   SET PROC_STAT_CD = #{procStatCd}, MOD_USER = #{modUser}, MOD_DT = NOW()
 WHERE REQ_NO = #{reqNo}

UPDATE INV.CONCIERGE_PARKING
   SET PMS_SYNC_YN = #{pmsSyncYn}, MOD_USER = #{modUser}, MOD_DT = NOW()
 WHERE REQ_NO = #{reqNo}

UPDATE INV.CONCIERGE_LATE_CO
   SET PROC_STAT_CD = #{procStatCd}, MOD_USER = #{modUser}, MOD_DT = NOW()
 WHERE REQ_NO = #{reqNo}

UPDATE INV.CCS_DEPARTMENT
SET DEPT_NM = #{deptNm}, SORT_ORD = #{sortOrd}, USE_YN = #{useYn}, MOD_USER = 'ADMIN', MOD_DT = NOW()
WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd} AND DEPT_CD = #{deptCd}

mapper.select:
SELECT TASK_ID, PROP_CD, CMPX_CD, DEPT_CD, SOURCE_TYPE, SOURCE_REF_NO,
       TITLE, MEMO, RM_NO, ASSIGNEE_ID, STATUS_CD, CREATED_AT, UPDATED_AT
  FROM INV.CCS_TASK
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}

   AND DEPT_CD = #{deptCd}


   AND STATUS_CD = #{statusCd}

 ORDER BY CREATED_AT DESC

SELECT COUNT(*) AS TOTAL_CNT, SUM(CASE WHEN STATUS_CD = 'DONE' THEN 1 ELSE 0 END) AS DONE_CNT, AVG(CASE WHEN STATUS_CD = 'DONE' THEN TIMESTAMPDIFF(MINUTE, CREATED_AT, UPDATED_AT) END) AS AVG_MINUTES FROM INV.CCS_TASK WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}
AND DEPT_CD = #{deptCd}
AND DATE(CREATED_AT) = CURDATE()
